export function getSiteById(id: number): Site | undefined { return sites.find((s) => s.id === id); }
export function getEmployeeById(id: string): Employee | undefined { return employees.find((e) => e.id === id); }
export function getWorkflowById(id: string): Workflow | undefined { return [...onboardingWorkflows, ...offboardingWorkflows, ...transferWorkflows].find((w) => w.id === id); }
export function getWorkflowsByType(type: "onboarding" | "offboarding" | "transfer"): Workflow[] { if (type === "onboarding") return onboardingWorkflows; if (type === "offboarding") return offboardingWorkflows; return transferWorkflows; }
export function getEmployeesBySite(siteId: number): Employee[] { return employees.filter((e) => e.siteId === siteId); }
export function getActiveWorkflowCount(): number { return onboardingWorkflows.length + offboardingWorkflows.length + transferWorkflows.length; }
